from strawberry import Schema, Object, Field, ID
from strawberry.sqlalchemy import SQLAlchemyConnection
from sqlalchemy import create_engine, Column, Integer, String, ForeignKey
from sqlalchemy.orm import relationship, declarative_base

# SQLAlchemy models
Base = declarative_base()

class Product(Base):
    __tablename__ = 'products'
    id = Column(Integer, primary_key=True)
    name = Column(String)
    description = Column(String)

class Review(Base):
    __tablename__ = 'reviews'
    id = Column(Integer, primary_key=True)
    product_id = Column(Integer, ForeignKey('products.id'))
    author = Column(String)
    content = Column(String)

class Seller(Base):
    __tablename__ = 'sellers'
    id = Column(Integer, primary_key=True)
    name = Column(String)

class Category(Base):
    __tablename__ = 'categories'
    id = Column(Integer, primary_key=True)
    name = Column(String)

class Image(Base):
    __tablename__ = 'images'
    id = Column(Integer, primary_key=True)
    product_id = Column(Integer, ForeignKey('products.id'))
    url = Column(String)

# GraphQL schema
@strawberry.type
class ProductType:
    id: ID
    name: str
    description: str
    reviews: SQLAlchemyConnection[Review]
    seller: SQLAlchemyConnection[Seller]
    category: SQLAlchemyConnection[Category]
    images: SQLAlchemyConnection[Image]

@strawberry.type
class Query:
    products: SQLAlchemyConnection[ProductType]

schema = Schema(query=Query)

